def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Define inputs explicitly
    min_lat, min_lon = 47.5, -122.4
    max_lat, max_lon = 47.7, -122.2

    # Step 1: Search Hospitals
    execution_log.append("Step 1: Searching for hospitals in Seattle bbox")
    raw_hospitals = call_tool('osm-mcp-server_search_category', {
        'category': 'amenity',
        'subcategories': ['hospital'],
        'min_latitude': min_lat, 'min_longitude': min_lon,
        'max_latitude': max_lat, 'max_longitude': max_lon
    })
    execution_log.append(f"[RAW] {str(raw_hospitals)[:200]}")

    # Parse hospitals output
    hospitals_data = json.loads(raw_hospitals) if isinstance(raw_hospitals, str) else raw_hospitals
    hospitals_list = []
    # Handle various response shapes (list directly, or wrapped in result/places)
    if isinstance(hospitals_data, list):
        hospitals_list = hospitals_data
    elif isinstance(hospitals_data, dict):
        res = hospitals_data.get('result', [])
        if isinstance(res, list):
            hospitals_list = res
        elif isinstance(res, dict) and 'places' in res:
            hospitals_list = res.get('places', [])
        elif 'places' in hospitals_data:
            hospitals_list = hospitals_data.get('places', [])

    hospital_count = len(hospitals_list)
    execution_log.append(f"Found {hospital_count} hospitals")

    classification = "Unknown"
    trials_found = 0

    # Branching Logic
    if hospital_count > 2:
        execution_log.append("Branch A: High Density (>2 hospitals)")
        h1 = hospitals_list[0]
        h2 = hospitals_list[1]

        # Extract coords safely
        def get_coord(obj, keys):
            for k in keys:
                if k in obj: return obj[k]
            return None

        h1_lat = get_coord(h1, ['lat', 'latitude']) or h1.get('location', {}).get('lat')
        h1_lon = get_coord(h1, ['lon', 'longitude']) or h1.get('location', {}).get('lon')
        h2_lat = get_coord(h2, ['lat', 'latitude']) or h2.get('location', {}).get('lat')
        h2_lon = get_coord(h2, ['lon', 'longitude']) or h2.get('location', {}).get('lon')

        execution_log.append(f"Analyzing commute between coords ({h1_lat},{h1_lon}) and ({h2_lat},{h2_lon})")

        raw_commute = call_tool('osm-mcp-server_analyze_commute', {
            'home_latitude': float(h1_lat), 'home_longitude': float(h1_lon),
            'work_latitude': float(h2_lat), 'work_longitude': float(h2_lon),
            'modes': ['car']
        })
        execution_log.append(f"[RAW] {str(raw_commute)[:200]}")
        commute_data = json.loads(raw_commute) if isinstance(raw_commute, str) else raw_commute

        # Extract duration
        duration = 1000 # Default high if fail
        try:
            res_inner = commute_data.get('result', {})
            # Try typical paths: result['car']['summary']['duration'] or result['car']['duration']
            car_data = res_inner.get('car', {})
            if 'summary' in car_data:
                duration = car_data.get('summary', {}).get('duration', 1000)
            else:
                duration = car_data.get('duration', 1000)
        except Exception as e:
            execution_log.append(f"Error parsing duration: {e}")

        execution_log.append(f"Commute duration: {duration} seconds")

        if float(duration) < 600:
            execution_log.append("Condition: < 600s -> Medical Hub")
            classification = "Medical Hub"

            raw_trials = call_tool('clinicaltrialsgov-mcp-server_clinicaltrials_list_studies', {
                'query': {'cond': 'Cardiology'},
                'filter': {
                    'overallStatus': ['RECRUITING'],
                    'geo': {'latitude': float(h1_lat), 'longitude': float(h1_lon), 'radius': 2000, 'unit': 'm'}
                },
                'pageSize': 5
            })
        else:
            execution_log.append("Condition: >= 600s -> Distributed Cluster")
            classification = "Distributed Cluster"

            raw_meet = call_tool('osm-mcp-server_suggest_meeting_point', {
                'locations': [{'latitude': float(h1_lat), 'longitude': float(h1_lon)}, 
                              {'latitude': float(h2_lat), 'longitude': float(h2_lon)}],
                'venue_type': 'cafe'
            })
            meet_data = json.loads(raw_meet) if isinstance(raw_meet, str) else raw_meet

            # Extract center safely
            # result might be dict with 'meeting_point' or 'center'
            res_meet = meet_data.get('result', {})
            c_lat = res_meet.get('latitude') or res_meet.get('center', {}).get('latitude') or 47.6
            c_lon = res_meet.get('longitude') or res_meet.get('center', {}).get('longitude') or -122.3

            raw_trials = call_tool('clinicaltrialsgov-mcp-server_clinicaltrials_list_studies', {
                'query': {'cond': 'Neurology'},
                'filter': {
                    'geo': {'latitude': float(c_lat), 'longitude': float(c_lon), 'radius': 2000, 'unit': 'm'}
                },
                'pageSize': 5
            })

    else:
        execution_log.append("Branch B: Low Density (<=2 hospitals)")
        raw_unis = call_tool('osm-mcp-server_search_category', {
            'category': 'amenity',
            'subcategories': ['university'],
            'min_latitude': min_lat, 'min_longitude': min_lon,
            'max_latitude': max_lat, 'max_longitude': max_lon
        })
        execution_log.append(f"[RAW] {str(raw_unis)[:200]}")
        unis_data = json.loads(raw_unis) if isinstance(raw_unis, str) else raw_unis
        unis_list = []
        if isinstance(unis_data, list):
             unis_list = unis_data
        elif isinstance(unis_data, dict):
             unis_list = unis_data.get('result', [])
             if isinstance(unis_list, dict) and 'places' in unis_list: unis_list = unis_list['places']

        if len(unis_list) > 0:
            execution_log.append("Condition: Universities found -> Academic Center")
            classification = "Academic Center"
            u1 = unis_list[0]
            u_lat = u1.get('lat') or u1.get('latitude') or u1.get('location', {}).get('lat')
            u_lon = u1.get('lon') or u1.get('longitude') or u1.get('location', {}).get('lon')

            raw_trials = call_tool('clinicaltrialsgov-mcp-server_clinicaltrials_list_studies', {
                'query': {'cond': 'Pediatrics'},
                'filter': {
                    'geo': {'latitude': float(u_lat), 'longitude': float(u_lon), 'radius': 2000, 'unit': 'm'}
                },
                'pageSize': 5
            })
        else:
            execution_log.append("Condition: No universities -> Remote Region")
            classification = "Remote Region"
            raw_trials = call_tool('clinicaltrialsgov-mcp-server_clinicaltrials_list_studies', {
                'query': {'cond': 'Telemedicine'},
                'pageSize': 5
            })

    execution_log.append(f"[RAW Trials] {str(raw_trials)[:200]}")
    trials_data = json.loads(raw_trials) if isinstance(raw_trials, str) else raw_trials

    # Extract totalCount defensively
    trials_found = trials_data.get('totalCount', 0)
    if not trials_found and 'result' in trials_data:
        res_t = trials_data['result']
        if isinstance(res_t, dict):
            trials_found = res_t.get('totalCount', 0)
            if not trials_found and 'studies' in res_t:
                 trials_found = len(res_t['studies'])

    # Final Memory Step
    execution_log.append(f"Step 3: Storing result. Class: {classification}, Count: {trials_found}")
    raw_mem = call_tool('memory_create_entities', {
        'entities': [{
            'name': 'Seattle Feasibility',
            'entityType': 'Analysis',
            'observations': [f"Classification: {classification}", f"Total Trials Found: {trials_found}"]
        }]
    })
    execution_log.append(f"[RAW] {str(raw_mem)[:200]}")

    return "\n".join(execution_log)

def generate_reference_answer():
    import json
    from mcp_client import call_tool

    execution_log = []

    # Step 1: Search ArXiv
    execution_log.append("Step 1: Searching ArXiv for 'Quantum Error Correction'")
    # ✅ Correct 2-argument call format
    raw_search = call_tool('arxiv_search_papers', {'query': 'Quantum Error Correction', 'max_results': 3})
    execution_log.append(f"[RAW] {str(raw_search)[:200]}")

    # Parse results safely
    search_results = []
    if isinstance(raw_search, list):
        search_results = raw_search
    elif isinstance(raw_search, str) and raw_search.strip():
        try:
            search_results = json.loads(raw_search)
        except:
            search_results = []

    # Defensive extraction of list from dict if wrapped
    if isinstance(search_results, dict):
        search_results = search_results.get('results', search_results.get('papers', []))

    first_paper = None
    pub_year = 0

    if search_results and isinstance(search_results, list) and len(search_results) > 0:
        first_paper = search_results[0]
        # Defensive field access
        pub_date = first_paper.get('published', '')
        execution_log.append(f"First paper date: {pub_date}")
        # Assume ISO format YYYY-MM-DD or similar
        if len(str(pub_date)) >= 4 and str(pub_date)[:4].isdigit():
            pub_year = int(str(pub_date)[:4])

    branch_taken = "Unknown"

    # Step 2: Condition Check
    if pub_year >= 2023:
        branch_taken = "Modern"
        execution_log.append(f"Condition Met: Year {pub_year} >= 2023. Executing Notion/Slack branch.")

        # Notion Action
        children_blocks = []
        for paper in search_results:
            title = paper.get('title', 'Unknown Title')
            children_blocks.append({
                "bulleted_list_item": {
                    "rich_text": [{ "text": { "content": title } }]
                }
            })

        notion_args = {
            "parent": { "page_id": "12345678-1234-1234-1234-123456789012" },
            "properties": {
                "title": [
                    { "text": { "content": "QEC Modern Findings" } }
                ]
            },
            "children": children_blocks
        }

        raw_notion = call_tool('notion_API-post-page', notion_args)
        execution_log.append(f"[RAW Notion] {str(raw_notion)[:200]}")

        # Slack Action
        slack_args = {
            "channel_id": "C9876543210",
            "payload": "Modern QEC papers logged to Notion."
        }
        raw_slack = call_tool('slack_conversations_add_message', slack_args)
        execution_log.append(f"[RAW Slack] {str(raw_slack)[:200]}")

    else:
        branch_taken = "Legacy"
        execution_log.append(f"Condition Met: Year {pub_year} < 2023 (or invalid). Executing Email branch.")

        if first_paper:
            title = first_paper.get('title', 'Unknown Title')
            summary = first_paper.get('summary', 'No summary available')

            email_args = {
                "to": "archive@research.org",
                "subject": "Legacy QEC Paper detected",
                "body": f"Title: {title}\n\nAbstract: {summary}"
            }

            raw_email = call_tool('google-workspace_send_email', email_args)
            execution_log.append(f"[RAW Email] {str(raw_email)[:200]}")
        else:
            execution_log.append("Error: No papers found to process for Legacy branch.")

    final_msg = f"Branch executed: {branch_taken}. First paper title: {first_paper.get('title', 'N/A') if first_paper else 'N/A'}"
    execution_log.append(f"Final Output: {final_msg}")

    return "\n".join(execution_log)
